import { useState, useMemo } from "react";

// ─── LOGO (base64, doré sur fond marine) ─────────────────────────────────
const LOGO_SRC = "data:image/jpeg;base64,";

// ─── CHARTE GRAPHIQUE BDS ─────────────────────────────────────────────────
const MARINE = "#000131";
const OR = "#D4AF37";
const BLANC = "#FFFFFF";

// ─── EMAILJS CONFIG ────────────────────────────────────────────────────────
const EMAILJS_SERVICE_ID = "service_t51wus8";
const EMAILJS_TEMPLATE_ADMIN = "template_slix1ni"; // récap complet -> BDS
const EMAILJS_TEMPLATE_PROSPECT = "template_6zrwttl"; // récap -> prospect
const EMAILJS_PUBLIC_KEY = "H456JnEh4IFv_91wc";

// ─── BASE DE PRIX SIMPLIFIÉE (pièces sèches, V1) ──────────────────────────
// Prix "moy" issus de la base interne BDS, majorés de +7,5% (marge de bonne
// surprise). Fourchette affichée : ±15% autour de ce prix moyen majoré.
// Confiance : élevée sur peinture/sol (postes stables), moyenne sur fenêtre
// (une seule variante retenue : PVC 2 vantaux, pour rester simple).
const PRIX = {
  peintureMur: { label: "Peinture mur (bon état, 2 couches)", unite: "m²", prix: 23.65 },
  peinturePlafond: { label: "Peinture plafond (bon état, 2 couches)", unite: "m²", prix: 26.88 },
  solParquet: { label: "Parquet flottant (fourniture + pose)", unite: "m²", prix: 43.0 },
  solCarrelage: { label: "Carrelage grès cérame (fourniture + pose)", unite: "m²", prix: 80.63 },
  solPVC: { label: "Sol PVC / vinyle (fourniture + pose)", unite: "m²", prix: 37.63 },
  fenetre: { label: "Fenêtre PVC 2 vantaux (fourniture + pose)", unite: "U", prix: 698.75 },
  prise: { label: "Point prise électrique (fourniture + pose)", unite: "U", prix: 96.75 },
  pointLumineux: { label: "Point lumineux (fourniture + pose)", unite: "U", prix: 139.75 },
};

const TYPES_PIECE = [
  { id: "chambre", label: "Chambre", icon: "🛏️" },
  { id: "salon", label: "Salon / Séjour", icon: "🛋️" },
  { id: "bureau", label: "Bureau", icon: "💼" },
  { id: "entree", label: "Couloir / Entrée", icon: "🚪" },
  { id: "wc", label: "WC", icon: "🚽" },
];

const TYPES_SOL = [
  { id: "solParquet", label: "Parquet flottant" },
  { id: "solCarrelage", label: "Carrelage" },
  { id: "solPVC", label: "Sol PVC / vinyle" },
];

export default function EstimateurBDS() {
  const [etape, setEtape] = useState("contact"); // contact | piece | dimensions | bouquet | resultat | fin
  const [contact, setContact] = useState({
    prenom: "", nom: "", email: "", telephone: "",
    delai: "", statut: "", optin: false,
  });
  const [pieces, setPieces] = useState([]); // pièces validées
  const [pieceCourante, setPieceCourante] = useState(null);
  const [envoiEnCours, setEnvoiEnCours] = useState(false);
  const [envoiStatut, setEnvoiStatut] = useState(null); // null | "ok" | "erreur"
  const [erreurs, setErreurs] = useState({});

  // ─── Nouvelle pièce (init) ───────────────────────────────────────────────
  function nouvellePiece() {
    setPieceCourante({
      type: null,
      surface: "",
      nbFenetres: 0,
      travaux: {
        peintureMur: false,
        peinturePlafond: false,
        sol: null, // null | "solParquet" | "solCarrelage" | "solPVC"
        fenetre: false,
        electricite: { actif: false, prises: 0, points: 0 },
      },
    });
    setEtape("piece");
  }

  // ─── Calcul du budget d'une pièce ────────────────────────────────────────
  function calculPiece(p) {
    const surf = parseFloat(p.surface) || 0;
    let moyen = 0;
    const detail = [];

    if (p.travaux.peintureMur) {
      const m = surf * PRIX.peintureMur.prix;
      moyen += m;
      detail.push({ ...PRIX.peintureMur, qte: surf, total: m });
    }
    if (p.travaux.peinturePlafond) {
      const m = surf * PRIX.peinturePlafond.prix;
      moyen += m;
      detail.push({ ...PRIX.peinturePlafond, qte: surf, total: m });
    }
    if (p.travaux.sol) {
      const ref = PRIX[p.travaux.sol];
      const m = surf * ref.prix;
      moyen += m;
      detail.push({ ...ref, qte: surf, total: m });
    }
    if (p.travaux.fenetre && p.nbFenetres > 0) {
      const m = p.nbFenetres * PRIX.fenetre.prix;
      moyen += m;
      detail.push({ ...PRIX.fenetre, qte: p.nbFenetres, total: m });
    }
    if (p.travaux.electricite.actif) {
      if (p.travaux.electricite.prises > 0) {
        const m = p.travaux.electricite.prises * PRIX.prise.prix;
        moyen += m;
        detail.push({ ...PRIX.prise, qte: p.travaux.electricite.prises, total: m });
      }
      if (p.travaux.electricite.points > 0) {
        const m = p.travaux.electricite.points * PRIX.pointLumineux.prix;
        moyen += m;
        detail.push({ ...PRIX.pointLumineux, qte: p.travaux.electricite.points, total: m });
      }
    }

    const bas = moyen * 0.85;
    const haut = moyen * 1.15;
    return { moyen, bas, haut, detail };
  }

  const totalGlobal = useMemo(() => {
    let bas = 0, haut = 0, moyen = 0;
    pieces.forEach((p) => {
      const c = calculPiece(p);
      bas += c.bas; haut += c.haut; moyen += c.moyen;
    });
    return { bas, haut, moyen };
  }, [pieces]);

  // ─── Validation contact ──────────────────────────────────────────────────
  function validerContact() {
    const err = {};
    if (!contact.prenom.trim()) err.prenom = "Prénom requis";
    if (!contact.nom.trim()) err.nom = "Nom requis";
    if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(contact.email)) err.email = "Email invalide";
    if (!contact.telephone.trim()) err.telephone = "Téléphone requis";
    if (!contact.delai) err.delai = "Sélectionnez un délai";
    if (!contact.statut) err.statut = "Sélectionnez un statut";
    if (!contact.optin) err.optin = "Consentement requis pour continuer";
    setErreurs(err);
    if (Object.keys(err).length === 0) {
      nouvellePiece();
    }
  }

  // ─── Validation étape pièce/dimensions/bouquet regroupée ────────────────
  function validerPieceEtSuivant() {
    const err = {};
    if (!pieceCourante.type) err.type = "Choisissez un type de pièce";
    if (!pieceCourante.surface || parseFloat(pieceCourante.surface) <= 0) err.surface = "Surface requise";
    setErreurs(err);
    if (Object.keys(err).length === 0) setEtape("bouquet");
  }

  function validerBouquetEtCalculer() {
    const t = pieceCourante.travaux;
    const auMoinsUn =
      t.peintureMur || t.peinturePlafond || t.sol || t.fenetre || t.electricite.actif;
    if (!auMoinsUn) {
      setErreurs({ bouquet: "Sélectionnez au moins un poste de travaux" });
      return;
    }
    setErreurs({});
    setPieces([...pieces, pieceCourante]);
    setEtape("resultat");
  }

  function ajouterAutrePiece() {
    nouvellePiece();
  }

  // ─── Envoi mail via EmailJS ───────────────────────────────────────────────
  async function envoyerRecap() {
    setEnvoiEnCours(true);
    setEnvoiStatut(null);
    try {
      const recapTexte = pieces
        .map((p, i) => {
          const c = calculPiece(p);
          const label = TYPES_PIECE.find((t) => t.id === p.type)?.label || p.type;
          const lignes = c.detail
            .map((d) => `   • ${d.label} : ${d.qte} ${d.unite} → ${Math.round(d.total)} €`)
            .join("\n");
          return `Pièce ${i + 1} — ${label} (${p.surface} m²)\n${lignes}\n   Fourchette : ${Math.round(c.bas)} € - ${Math.round(c.haut)} €`;
        })
        .join("\n\n");

      const templateParams = {
        prenom: contact.prenom,
        nom: contact.nom,
        email: contact.email,
        telephone: contact.telephone,
        delai: contact.delai,
        statut: contact.statut,
        nb_pieces: pieces.length,
        recap_detail: recapTexte,
        budget_bas: Math.round(totalGlobal.bas),
        budget_haut: Math.round(totalGlobal.haut),
        date: new Date().toLocaleDateString("fr-FR"),
      };

      // Chargement dynamique du SDK EmailJS (CDN)
      if (!window.emailjs) {
        await new Promise((resolve, reject) => {
          const script = document.createElement("script");
          script.src = "https://cdn.jsdelivr.net/npm/@emailjs/browser@4/dist/email.min.js";
          script.onload = resolve;
          script.onerror = reject;
          document.head.appendChild(script);
        });
        window.emailjs.init({ publicKey: EMAILJS_PUBLIC_KEY });
      }

      await window.emailjs.send(EMAILJS_SERVICE_ID, EMAILJS_TEMPLATE_ADMIN, templateParams);
      await window.emailjs.send(EMAILJS_SERVICE_ID, EMAILJS_TEMPLATE_PROSPECT, templateParams);

      setEnvoiStatut("ok");
      setEtape("fin");
    } catch (e) {
      console.error("Erreur envoi EmailJS:", e);
      const detail =
        e?.text || e?.message || (typeof e === "string" ? e : JSON.stringify(e));
      setEnvoiStatut(detail || "Erreur inconnue");
    } finally {
      setEnvoiEnCours(false);
    }
  }

  // ─── STYLES COMMUNS ────────────────────────────────────────────────────
  const styles = {
    page: {
      minHeight: "100vh",
      background: "#F7F7F9",
      fontFamily: "'Montserrat', 'Helvetica Neue', Arial, sans-serif",
      display: "flex",
      flexDirection: "column",
      alignItems: "center",
      padding: "0 0 40px 0",
    },
    header: {
      width: "100%",
      background: MARINE,
      padding: "20px 24px",
      display: "flex",
      alignItems: "center",
      gap: 16,
      boxSizing: "border-box",
    },
    logo: { height: 52 },
    headerTitle: { color: BLANC, fontSize: 18, fontWeight: 600, margin: 0 },
    headerSub: { color: OR, fontSize: 12, margin: 0, fontWeight: 500 },
    card: {
      background: BLANC,
      borderRadius: 12,
      padding: 32,
      maxWidth: 560,
      width: "100%",
      boxShadow: "0 2px 16px rgba(0,1,49,0.08)",
      marginTop: 32,
      boxSizing: "border-box",
    },
    h2: { color: MARINE, fontSize: 22, fontWeight: 700, marginTop: 0, marginBottom: 8 },
    p: { color: "#444", fontSize: 14, lineHeight: 1.5, marginTop: 0, marginBottom: 24 },
    label: { display: "block", color: MARINE, fontSize: 13, fontWeight: 600, marginBottom: 6, marginTop: 16 },
    input: {
      width: "100%",
      padding: "12px 14px",
      borderRadius: 8,
      border: "1.5px solid #DDD",
      fontSize: 14,
      fontFamily: "inherit",
      boxSizing: "border-box",
      outline: "none",
    },
    inputErr: { borderColor: "#C0392B" },
    err: { color: "#C0392B", fontSize: 12, marginTop: 4 },
    select: {
      width: "100%",
      padding: "12px 14px",
      borderRadius: 8,
      border: "1.5px solid #DDD",
      fontSize: 14,
      fontFamily: "inherit",
      boxSizing: "border-box",
      background: BLANC,
    },
    btnPrimary: {
      background: MARINE,
      color: BLANC,
      border: "none",
      borderRadius: 8,
      padding: "14px 28px",
      fontSize: 15,
      fontWeight: 700,
      cursor: "pointer",
      width: "100%",
      marginTop: 24,
      fontFamily: "inherit",
    },
    btnSecondary: {
      background: "transparent",
      color: MARINE,
      border: `1.5px solid ${MARINE}`,
      borderRadius: 8,
      padding: "12px 24px",
      fontSize: 14,
      fontWeight: 600,
      cursor: "pointer",
      width: "100%",
      marginTop: 10,
      fontFamily: "inherit",
    },
    btnGold: {
      background: OR,
      color: MARINE,
      border: "none",
      borderRadius: 8,
      padding: "14px 28px",
      fontSize: 15,
      fontWeight: 700,
      cursor: "pointer",
      width: "100%",
      marginTop: 24,
      fontFamily: "inherit",
    },
    tileGrid: { display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12, marginTop: 8 },
    tile: (active) => ({
      border: `1.5px solid ${active ? MARINE : "#DDD"}`,
      background: active ? MARINE : BLANC,
      color: active ? BLANC : MARINE,
      borderRadius: 10,
      padding: "16px 12px",
      textAlign: "center",
      cursor: "pointer",
      fontSize: 13,
      fontWeight: 600,
      transition: "all 0.15s",
    }),
    checkboxRow: {
      display: "flex",
      alignItems: "center",
      gap: 10,
      padding: "12px 14px",
      border: "1.5px solid #DDD",
      borderRadius: 8,
      marginTop: 10,
      cursor: "pointer",
    },
    checkboxRowActive: { borderColor: MARINE, background: "#F0F0F5" },
    stepper: { display: "flex", gap: 6, marginBottom: 8 },
    stepDot: (active) => ({
      height: 4,
      flex: 1,
      borderRadius: 2,
      background: active ? OR : "#E5E5E5",
    }),
    badge: {
      display: "inline-block",
      background: "#F0F0F5",
      color: MARINE,
      fontSize: 11,
      fontWeight: 700,
      padding: "4px 10px",
      borderRadius: 20,
      marginBottom: 12,
    },
    footer: { color: "#999", fontSize: 11, textAlign: "center", marginTop: 24, lineHeight: 1.6 },
  };

  const STEP_ORDER = ["contact", "piece", "bouquet", "resultat"];

  return (
    <div style={styles.page}>
      <div style={styles.header}>
        <img src={LOGO_SRC} alt="BD Solutions Travaux" style={styles.logo} />
        <div>
          <p style={styles.headerTitle}>BD Solutions Travaux</p>
          <p style={styles.headerSub}>Estimateur de budget travaux — gratuit &amp; sans engagement</p>
        </div>
      </div>

      <div style={styles.card}>
        {/* ─── ÉTAPE CONTACT ─────────────────────────────────────────── */}
        {etape === "contact" && (
          <>
            <span style={styles.badge}>ÉTAPE 1/4</span>
            <h2 style={styles.h2}>Vos coordonnées</h2>
            <p style={styles.p}>
              Renseignez vos informations pour recevoir votre estimation par email, sans engagement de notre part.
            </p>

            <label style={styles.label}>Prénom *</label>
            <input
              style={{ ...styles.input, ...(erreurs.prenom ? styles.inputErr : {}) }}
              value={contact.prenom}
              onChange={(e) => setContact({ ...contact, prenom: e.target.value })}
            />
            {erreurs.prenom && <div style={styles.err}>{erreurs.prenom}</div>}

            <label style={styles.label}>Nom *</label>
            <input
              style={{ ...styles.input, ...(erreurs.nom ? styles.inputErr : {}) }}
              value={contact.nom}
              onChange={(e) => setContact({ ...contact, nom: e.target.value })}
            />
            {erreurs.nom && <div style={styles.err}>{erreurs.nom}</div>}

            <label style={styles.label}>Email *</label>
            <input
              type="email"
              style={{ ...styles.input, ...(erreurs.email ? styles.inputErr : {}) }}
              value={contact.email}
              onChange={(e) => setContact({ ...contact, email: e.target.value })}
            />
            {erreurs.email && <div style={styles.err}>{erreurs.email}</div>}

            <label style={styles.label}>Téléphone *</label>
            <input
              type="tel"
              style={{ ...styles.input, ...(erreurs.telephone ? styles.inputErr : {}) }}
              value={contact.telephone}
              onChange={(e) => setContact({ ...contact, telephone: e.target.value })}
            />
            {erreurs.telephone && <div style={styles.err}>{erreurs.telephone}</div>}

            <label style={styles.label}>Délai envisagé pour le projet *</label>
            <select
              style={{ ...styles.select, ...(erreurs.delai ? styles.inputErr : {}) }}
              value={contact.delai}
              onChange={(e) => setContact({ ...contact, delai: e.target.value })}
            >
              <option value="">Sélectionnez...</option>
              <option value="Moins de 3 mois">Moins de 3 mois</option>
              <option value="3 à 6 mois">3 à 6 mois</option>
              <option value="6 à 12 mois">6 à 12 mois</option>
              <option value="Plus d'un an / pas encore défini">Plus d'un an / pas encore défini</option>
            </select>
            {erreurs.delai && <div style={styles.err}>{erreurs.delai}</div>}

            <label style={styles.label}>Vous êtes *</label>
            <select
              style={{ ...styles.select, ...(erreurs.statut ? styles.inputErr : {}) }}
              value={contact.statut}
              onChange={(e) => setContact({ ...contact, statut: e.target.value })}
            >
              <option value="">Sélectionnez...</option>
              <option value="Propriétaire">Propriétaire</option>
              <option value="Futur propriétaire (achat en cours)">Futur propriétaire (achat en cours)</option>
              <option value="Locataire">Locataire</option>
            </select>
            {erreurs.statut && <div style={styles.err}>{erreurs.statut}</div>}

            <div
              style={{ ...styles.checkboxRow, ...(contact.optin ? styles.checkboxRowActive : {}) }}
              onClick={() => setContact({ ...contact, optin: !contact.optin })}
            >
              <input type="checkbox" checked={contact.optin} onChange={() => {}} style={{ width: 18, height: 18 }} />
              <span style={{ fontSize: 12.5, color: "#444" }}>
                J'accepte d'être recontacté(e) par BD Solutions Travaux au sujet de mon projet. Mes données ne sont
                utilisées que dans ce cadre. *
              </span>
            </div>
            {erreurs.optin && <div style={styles.err}>{erreurs.optin}</div>}

            <button style={styles.btnPrimary} onClick={validerContact}>
              Commencer mon estimation →
            </button>
          </>
        )}

        {/* ─── ÉTAPE PIÈCE + DIMENSIONS ──────────────────────────────── */}
        {etape === "piece" && pieceCourante && (
          <>
            <span style={styles.badge}>ÉTAPE 2/4 — PIÈCE {pieces.length + 1}</span>
            <h2 style={styles.h2}>Quelle pièce souhaitez-vous rénover ?</h2>
            <p style={styles.p}>Sélectionnez le type de pièce et indiquez ses dimensions.</p>

            <div style={styles.tileGrid}>
              {TYPES_PIECE.map((t) => (
                <div
                  key={t.id}
                  style={styles.tile(pieceCourante.type === t.id)}
                  onClick={() => setPieceCourante({ ...pieceCourante, type: t.id })}
                >
                  <div style={{ fontSize: 22, marginBottom: 4 }}>{t.icon}</div>
                  {t.label}
                </div>
              ))}
            </div>
            {erreurs.type && <div style={styles.err}>{erreurs.type}</div>}

            <label style={styles.label}>Surface de la pièce (m²) *</label>
            <input
              type="number"
              min="1"
              style={{ ...styles.input, ...(erreurs.surface ? styles.inputErr : {}) }}
              value={pieceCourante.surface}
              onChange={(e) => setPieceCourante({ ...pieceCourante, surface: e.target.value })}
              placeholder="Ex : 12"
            />
            {erreurs.surface && <div style={styles.err}>{erreurs.surface}</div>}

            <label style={styles.label}>Nombre de fenêtres dans la pièce</label>
            <input
              type="number"
              min="0"
              style={styles.input}
              value={pieceCourante.nbFenetres}
              onChange={(e) =>
                setPieceCourante({ ...pieceCourante, nbFenetres: parseInt(e.target.value) || 0 })
              }
            />

            <button style={styles.btnPrimary} onClick={validerPieceEtSuivant}>
              Continuer →
            </button>
            {pieces.length > 0 && (
              <button style={styles.btnSecondary} onClick={() => setEtape("resultat_liste")}>
                Annuler et revenir au récapitulatif
              </button>
            )}
          </>
        )}

        {/* ─── ÉTAPE BOUQUET DE TRAVAUX ──────────────────────────────── */}
        {etape === "bouquet" && pieceCourante && (
          <>
            <span style={styles.badge}>ÉTAPE 3/4 — PIÈCE {pieces.length + 1}</span>
            <h2 style={styles.h2}>Quels travaux envisagez-vous ?</h2>
            <p style={styles.p}>Sélectionnez un ou plusieurs postes.</p>

            <div
              style={{ ...styles.checkboxRow, ...(pieceCourante.travaux.peintureMur ? styles.checkboxRowActive : {}) }}
              onClick={() =>
                setPieceCourante({
                  ...pieceCourante,
                  travaux: { ...pieceCourante.travaux, peintureMur: !pieceCourante.travaux.peintureMur },
                })
              }
            >
              <input type="checkbox" checked={pieceCourante.travaux.peintureMur} onChange={() => {}} style={{ width: 18, height: 18 }} />
              <span style={{ fontSize: 14, fontWeight: 600, color: MARINE }}>🎨 Peinture des murs</span>
            </div>

            <div
              style={{ ...styles.checkboxRow, ...(pieceCourante.travaux.peinturePlafond ? styles.checkboxRowActive : {}) }}
              onClick={() =>
                setPieceCourante({
                  ...pieceCourante,
                  travaux: { ...pieceCourante.travaux, peinturePlafond: !pieceCourante.travaux.peinturePlafond },
                })
              }
            >
              <input type="checkbox" checked={pieceCourante.travaux.peinturePlafond} onChange={() => {}} style={{ width: 18, height: 18 }} />
              <span style={{ fontSize: 14, fontWeight: 600, color: MARINE }}>🎨 Peinture du plafond</span>
            </div>

            <label style={styles.label}>🧱 Revêtement de sol</label>
            <div style={styles.tileGrid}>
              <div
                style={styles.tile(pieceCourante.travaux.sol === null)}
                onClick={() =>
                  setPieceCourante({ ...pieceCourante, travaux: { ...pieceCourante.travaux, sol: null } })
                }
              >
                Aucun
              </div>
              {TYPES_SOL.map((s) => (
                <div
                  key={s.id}
                  style={styles.tile(pieceCourante.travaux.sol === s.id)}
                  onClick={() =>
                    setPieceCourante({ ...pieceCourante, travaux: { ...pieceCourante.travaux, sol: s.id } })
                  }
                >
                  {s.label}
                </div>
              ))}
            </div>

            {pieceCourante.nbFenetres > 0 && (
              <div
                style={{ ...styles.checkboxRow, ...(pieceCourante.travaux.fenetre ? styles.checkboxRowActive : {}) }}
                onClick={() =>
                  setPieceCourante({
                    ...pieceCourante,
                    travaux: { ...pieceCourante.travaux, fenetre: !pieceCourante.travaux.fenetre },
                  })
                }
              >
                <input type="checkbox" checked={pieceCourante.travaux.fenetre} onChange={() => {}} style={{ width: 18, height: 18 }} />
                <span style={{ fontSize: 14, fontWeight: 600, color: MARINE }}>
                  🪟 Remplacement fenêtre(s) — {pieceCourante.nbFenetres} unité(s)
                </span>
              </div>
            )}

            <div
              style={{ ...styles.checkboxRow, ...(pieceCourante.travaux.electricite.actif ? styles.checkboxRowActive : {}) }}
              onClick={() =>
                setPieceCourante({
                  ...pieceCourante,
                  travaux: {
                    ...pieceCourante.travaux,
                    electricite: { ...pieceCourante.travaux.electricite, actif: !pieceCourante.travaux.electricite.actif },
                  },
                })
              }
            >
              <input type="checkbox" checked={pieceCourante.travaux.electricite.actif} onChange={() => {}} style={{ width: 18, height: 18 }} />
              <span style={{ fontSize: 14, fontWeight: 600, color: MARINE }}>💡 Électricité (prises / éclairage)</span>
            </div>

            {pieceCourante.travaux.electricite.actif && (
              <div style={{ display: "flex", gap: 12, marginTop: 10 }}>
                <div style={{ flex: 1 }}>
                  <label style={styles.label}>Nb prises</label>
                  <input
                    type="number"
                    min="0"
                    style={styles.input}
                    value={pieceCourante.travaux.electricite.prises}
                    onChange={(e) =>
                      setPieceCourante({
                        ...pieceCourante,
                        travaux: {
                          ...pieceCourante.travaux,
                          electricite: { ...pieceCourante.travaux.electricite, prises: parseInt(e.target.value) || 0 },
                        },
                      })
                    }
                  />
                </div>
                <div style={{ flex: 1 }}>
                  <label style={styles.label}>Nb points lumineux</label>
                  <input
                    type="number"
                    min="0"
                    style={styles.input}
                    value={pieceCourante.travaux.electricite.points}
                    onChange={(e) =>
                      setPieceCourante({
                        ...pieceCourante,
                        travaux: {
                          ...pieceCourante.travaux,
                          electricite: { ...pieceCourante.travaux.electricite, points: parseInt(e.target.value) || 0 },
                        },
                      })
                    }
                  />
                </div>
              </div>
            )}

            {erreurs.bouquet && <div style={styles.err}>{erreurs.bouquet}</div>}

            <button style={styles.btnPrimary} onClick={validerBouquetEtCalculer}>
              Voir mon estimation →
            </button>
            <button style={styles.btnSecondary} onClick={() => setEtape("piece")}>
              ← Retour
            </button>
          </>
        )}

        {/* ─── ÉTAPE RÉSULTAT (après ajout d'une pièce) ──────────────── */}
        {etape === "resultat" && (
          <>
            <span style={styles.badge}>ÉTAPE 4/4</span>
            <h2 style={styles.h2}>Votre estimation</h2>

            {pieces.map((p, i) => {
              const c = calculPiece(p);
              const label = TYPES_PIECE.find((t) => t.id === p.type)?.label || p.type;
              return (
                <div key={i} style={{ marginBottom: 18, paddingBottom: 14, borderBottom: "1px solid #EEE" }}>
                  <div style={{ fontWeight: 700, color: MARINE, fontSize: 14, marginBottom: 6 }}>
                    {label} — {p.surface} m²
                  </div>
                  {c.detail.map((d, j) => (
                    <div key={j} style={{ fontSize: 12.5, color: "#666", display: "flex", justifyContent: "space-between" }}>
                      <span>{d.label} ({d.qte} {d.unite})</span>
                      <span>{Math.round(d.total)} €</span>
                    </div>
                  ))}
                  <div style={{ fontSize: 13, fontWeight: 700, color: OR, marginTop: 6 }}>
                    Fourchette : {Math.round(c.bas).toLocaleString("fr-FR")} € – {Math.round(c.haut).toLocaleString("fr-FR")} €
                  </div>
                </div>
              );
            })}

            <div
              style={{
                background: MARINE,
                borderRadius: 10,
                padding: "18px 20px",
                textAlign: "center",
                marginTop: 8,
              }}
            >
              <div style={{ color: OR, fontSize: 12, fontWeight: 700, letterSpacing: 0.5 }}>
                BUDGET TOTAL ESTIMÉ
              </div>
              <div style={{ color: BLANC, fontSize: 26, fontWeight: 800, marginTop: 6 }}>
                {Math.round(totalGlobal.bas).toLocaleString("fr-FR")} € – {Math.round(totalGlobal.haut).toLocaleString("fr-FR")} €
              </div>
            </div>

            <p style={{ ...styles.p, fontSize: 11.5, color: "#888", marginTop: 16, marginBottom: 0 }}>
              Estimation indicative non contractuelle, à ±15 % autour d'un prix moyen constaté sur des chantiers
              comparables. Basée sur une grille tarifaire locale (zone Mont-de-Marsan et 80 km alentours) ; le prix
              réel peut varier selon la localisation exacte, l'état du support et l'accessibilité du chantier. Seul
              un devis d'artisan fait foi.
            </p>

            <button style={styles.btnGold} onClick={ajouterAutrePiece}>
              + Ajouter une autre pièce
            </button>
            <button style={styles.btnPrimary} onClick={envoyerRecap} disabled={envoiEnCours}>
              {envoiEnCours ? "Envoi en cours..." : "Recevoir mon récapitulatif par email"}
            </button>
            {envoiStatut && envoiStatut !== "ok" && (
              <div style={styles.err}>
                Erreur lors de l'envoi : {envoiStatut}
              </div>
            )}
          </>
        )}

        {/* ─── ÉTAPE FIN ──────────────────────────────────────────────── */}
        {etape === "fin" && (
          <>
            <div style={{ fontSize: 48, textAlign: "center", marginBottom: 12 }}>✅</div>
            <h2 style={{ ...styles.h2, textAlign: "center" }}>Merci {contact.prenom} !</h2>
            <p style={{ ...styles.p, textAlign: "center" }}>
              Votre récapitulatif vient de vous être envoyé par email. Notre équipe a également été notifiée et
              reviendra vers vous rapidement pour affiner votre projet.
            </p>
            <div
              style={{
                background: "#F0F0F5",
                borderRadius: 10,
                padding: 16,
                textAlign: "center",
                fontSize: 13,
                color: MARINE,
              }}
            >
              📞 06 85 27 10 42<br />
              ✉️ contact@bd-solutions-travaux.fr
            </div>
          </>
        )}
      </div>

      <div style={styles.footer}>
        BD Solutions Travaux — 63 rue Jean-Pierre Labarbe, 40000 Mont-de-Marsan
        <br />
        Cet outil fournit une estimation indicative et ne remplace pas un devis d'artisan.
      </div>
    </div>
  );
}
